const c = $('10_Claim_Contact').item.json.body[0];
const p = ($('20_Fetch_Partner').item.json.body || [])[0] || {};
const s = ($('25_Fetch_Settings').item.json.body || [])[0] || {};
const inbound = ($('30_Fetch_Inbound').item.json.body || []).map(m => ({ ts: m.created_at, role: 'lead', text: m.body }));
const outbound = ($('35_Fetch_Outbound').item.json.body || []).map(m => ({ ts: m.created_at, role: 'ai', text: m.body }));
const history = inbound.concat(outbound).sort((a,b) => a.ts.localeCompare(b.ts));
const aiName = s.ai_assistant_name || 'Ассистент';
const tone = s.ai_tone || 'formal';
const state = c.ai_state || 'greeting';

const systemPrompt = `Вы — ${aiName}, помощница партнёра InCruises ${p.name || ''}. Контактируете с клиентом партнёра в мессенджере.

# Идентичность
- Представляйтесь как ассистент партнёра, НЕ как сам партнёр. На прямой вопрос «ты бот?» отвечайте честно: «AI-ассистент».
- Никогда не давайте обещаний от имени партнёра.

# Тон и формат
- Обращение строго на «вы» (формальный тон).
- Короткие сообщения 1-2 предложения.
- Максимум 1 эмодзи на сообщение.
- Без markdown и списков. Обычный текст.

# Язык
- База — русский. Если контакт пишет на KZ/EN — переключитесь и держите этот язык.
- Не смешивайте языки в одном сообщении.

# Compliance (НАРУШАТЬ НЕЛЬЗЯ)
- Никогда не обещайте конкретный доход, гарантированную прибыль, сроки окупаемости.
- Никаких scarcity-тактик ("места заканчиваются", "только сегодня").
- Никаких медицинских, юридических, финансовых советов.
- На STOP/НЕ ПИШИТЕ → action='stop', intent='stop'.

# Этапы диалога
greeting → qualification → presentation → q_and_a → objection → close.
Текущий: ${state}. Двигайтесь органично.

# Эскалация (escalate=true ОБЯЗАТЕЛЬНО)
- Негатив/оскорбления → escalate_reason='negative'
- «оплачу/куда платить/готов начать» → escalate_reason='ready_to_pay', intent='ready_to_pay'
- Медиа от лида (картинка/голос/файл) → escalate_reason='media', intent='media_received'
- Не знаете ответа из БЗ → escalate_reason='no_kb'
- confidence<0.6 → escalate_reason='low_confidence'
При эскалации в text напишите контакту «секунду, передаю Сайре» (на его языке).

# Объекции
- «Нет денег» — стоимость относительно value, опция минимального тарифа
- «Нет времени» — passive side-доход, 1-2 часа в неделю
- «Пирамида/MLM» — честно признать модель, упор на реальный продукт (путешествия)
- «Не верю / негативный опыт» — эмпатия, попросить рассказать
- «Посоветоваться» — принять, предложить материалы
- «Подумаю» — принять, спросить какой вопрос остался
- «Не подхожу» — переформулировать мягко
- «Сложно» — разбить на шаги
Без давления. Возражение 2+ раз → эскалация.

# Контекст
Контакт: ${c.name || ''}, timezone ${c.timezone || 'Asia/Almaty'}.
Referral партнёра: ${p.referral_url || '(не задан)'}.

# Гибрид
- greeting/presentation/close — придерживайтесь шаблона, подставляйте имя.
- qualification/q_and_a/objection — генерируйте по правилам выше.

Выход — строго JSON по schema. Без markdown-обёртки.`;

const historyText = history.length === 0 ? '(история пуста)' : history.map(m => '[' + m.role + '] ' + m.text).join('\n');
const userPrompt = 'Имя контакта: ' + (c.name || '') + '\n\nПоследние сообщения:\n' + historyText + '\n\nСгенерируй следующее сообщение и метаданные строго в JSON по schema.';

const schema = {
  name: 'ai_reply',
  strict: true,
  schema: {
    type: 'object',
    additionalProperties: false,
    required: ['action','text','intent','escalate','escalate_reason','sentiment','confidence','next_state'],
    properties: {
      action: { type: 'string', enum: ['reply','defer','stop'] },
      text: { type: 'string' },
      intent: { type: 'string', enum: ['qualification','ready_to_pay','objection','media_received','stop','other'] },
      escalate: { type: 'boolean' },
      escalate_reason: { type: 'string', enum: ['negative','ready_to_pay','low_confidence','no_kb','media','none'] },
      sentiment: { type: 'string', enum: ['positive','neutral','negative'] },
      confidence: { type: 'number', minimum: 0, maximum: 1 },
      next_state: { type: 'string', enum: ['greeting','qualification','presentation','q_and_a','objection','close','paused','escalated','cold'] }
    }
  }
};

const openai_body = {
  model: 'gpt-4.1-mini',
  temperature: 0.3,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ],
  response_format: { type: 'json_schema', json_schema: schema }
};

return [{ json: {
  contact_id: c.id,
  partner_id: c.partner_id,
  contact_name: c.name,
  contact_phone: c.phone,
  contact_handle: c.messenger_handle,
  contact_messenger: c.messenger,
  current_state: state,
  openai_body
} }];

const upstream = $('40_Build_Prompt').item.json;
const resp = $json;
if (resp.error || (resp.body && resp.body.error)) {
  return [{ json: { ...upstream, ai_error: (resp.body && resp.body.error) || resp.error || resp.statusCode || 'unknown', ai_reply: null } }];
}
const raw = resp.body && resp.body.choices && resp.body.choices[0] && resp.body.choices[0].message && resp.body.choices[0].message.content;
let parsed = null;
try { parsed = JSON.parse(raw); } catch (e) { return [{ json: { ...upstream, ai_error: 'parse_failed: ' + e.message, ai_raw: raw, ai_reply: null } }]; }
return [{ json: { ...upstream, ai_reply: parsed, ai_raw: raw, ai_usage: resp.body && resp.body.usage } }];
